import{u as s,o as i,c as r,j as e,k as o,F as l,al as c,e as d,p as h}from"./chunks/framework.CPVRhMMt.js";const u=["markdown-url"],p={"data-allow-mismatch":"",style:{display:"none"}},v=JSON.parse('{"title":"Urban Heat Trend Monitor","description":"","frontmatter":{"layout":"page"},"headers":[],"params":{"narrative":"urban-heat-trend-monitor","file":"https://gtif-austria.github.io/public-narratives/urban-heat-trend-monitor.md","title":"Urban Heat Trend Monitor"},"relativePath":"narratives/urban-heat-trend-monitor.md","filePath":"narratives/[narrative].md"}'),m={name:"narratives/urban-heat-trend-monitor.md"},y=Object.assign(m,{setup(g){const a=h(!0);a.value=!1;const{params:n}=s();return(b,t)=>(i(),r("div",null,[e("client-only",null,[e("eox-storytelling",{"show-nav":"","markdown-url":o(n).file,"show-hero-scroll-indicator":"",class:"full-width",style:{transform:"translateY(calc(var(--vp-nav-height) - 2px))","margin-top":"calc(var(--vp-nav-height) * -1 - 90px + 48px)","margin-bottom":"var(--vp-nav-height)","--eox-storytelling-hero-height":"auto"}},null,8,u)]),e("div",p,[a.value?(i(),r(l,{key:0},[t[0]||(t[0]=c(' --- cover-image: https://workspace-ui-public.gtif-at-sc.hub-otc.eox.at/api/public/share/public-4wazei3y-02/UHTM_Wien/iStock-1173256779.jpg date: 2025-01-01 theme: Sustainable Cities tags: remote sensing, surface temperature, Sentinel-3 provider: OHB Digital Connect --- <h1 id="urban-heat-trend-monitor" tabindex="-1">Urban Heat Trend Monitor <a class="header-anchor" href="#urban-heat-trend-monitor" aria-label="Permalink to &quot;Urban Heat Trend Monitor &lt;!--{ as=&quot;img&quot; mode=&quot;hero&quot; src=&quot;https://workspace-ui-public.gtif-at-sc.hub-otc.eox.at/api/public/share/public-4wazei3y-02/UHTM_Wien/iStock-1173256779.jpg&quot; }--&gt;&quot;">​</a></h1><h3 id="turning-satellite-data-into-actionable-urban-cooling-strategies" tabindex="-1">Turning satellite data into actionable urban cooling strategies <a class="header-anchor" href="#turning-satellite-data-into-actionable-urban-cooling-strategies" aria-label="Permalink to &quot;Turning satellite data into actionable urban cooling strategies &lt;!--{ style=&quot;font-size:1.5rem;opacity:0.7;margin-top:1rem;&quot; }--&gt;&quot;">​</a></h3><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>Cities are increasingly exposed to rising temperatures due to climate change, with urban areas often experiencing significantly higher temperatures than surrounding rural regions. This phenomenon, known as the urban heat island effect, is caused by dense construction materials such as concrete and asphalt that absorb and store heat, reduced vegetation, and limited air circulation between buildings. Additional heat sources such as traffic, air conditioning systems, and industrial activity further intensify the problem <a href="https://publications.jrc.ec.europa.eu/repository/handle/JRC137891" target="_blank" rel="noreferrer">[1]</a>.</p><p>These elevated temperatures pose serious challenges. Heatwaves have become more frequent and severe, directly impacting public health, particularly for vulnerable populations such as the elderly and those with pre-existing conditions. Importantly, heat exposure is not evenly distributed across a city: some neighbourhoods experience much stronger heating due to differences in land use, green space availability, and urban structure.</p><p>Despite this growing risk, many cities lack detailed and continuous data to understand where and how heat develops over time. Traditional monitoring approaches are often limited in spatial resolution or coverage, making it difficult to identify local hotspots or long-term trends. Without reliable data, urban planners and policymakers struggle to design targeted mitigation measures such as green infrastructure, cooling strategies, or early warning systems. This creates an urgent need for scalable, data-driven tools that provide consistent, high-resolution insights into urban heat dynamics.</p><h2 id="proposed-solution" tabindex="-1">Proposed solution <a class="header-anchor" href="#proposed-solution" aria-label="Permalink to &quot;Proposed solution&quot;">​</a></h2><p>The Urban Heat Trend Monitor (UHTM) meets this need by providing a range of tools that enable the high-resolution visualisation of heat distribution within a city, the identification of heat trends over several years, and the calculation and display of urban areas with the same heat trend, thereby allowing local hotspots to be identified quickly and intuitively. For each of these areas, a detailed time-series analysis can be accessed, enabling the identification of patterns and extremes over the entire period as well as for specific seasons (e.g. summer). The UHTM service processes its results based on satellite data provided by Copernicus, the European Union’s Earth observation programme. It combines data from ESA’s Copernicus Sentinel-2 and Sentinel-3 satellites with OpenStreetMap elements to provide users with easily interpretable map layers that contain urban climate information. Super-resolution techniques enable the analysis of heat islands and temperature trends at the level of individual city districts.</p><p>The UHTM service has been developed to support a wide range of stakeholders, including urban planners, local authorities, environmental agencies and health authorities. Using the provided information, decision-makers can prioritise measures such as expanding green spaces, adapting building materials or implementing local cooling measures. The service enables cities to move from reactive responses to proactive planning, strengthening climate resilience and improving living conditions for urban populations.</p><h2 id="service" tabindex="-1">Service <a class="header-anchor" href="#service" aria-label="Permalink to &quot;Service&quot;">​</a></h2><p>The UHTM service provides a collection of tools for displaying heat distribution within a city in high resolution, determining heat trends over several years, and calculating and displaying urban areas with the same heat trend, enabling local hotspots to be identified quickly and intuitively. For each of these areas, a detailed time series analysis can be retrieved, enabling identification of patterns and extremes over the entire period as well as for specific periods of the year (e.g. summer). The UHTM service uses several key algorithms to transform satellite data into actionable heat insights:</p><ol><li><strong>Cloud‑free Index Generation</strong>: This algorithm uses optical Sentinel-2 satellite data to replace cloud-covered pixels with the most recent cloud-free data, thereby ensuring continuous and reliable datasets. This results in consistent and gap-free surface indices, such as NDVI and NDBI, which are applied as input for the further processing steps.</li><li>The <strong>Land Surface Temperature (LST) Downscaling</strong> algorithm improves the coarse 1 km resolution of Sentinel 3 thermal data by modelling the relationship between temperature and land cover characteristics derived from higher resolution indices, such as built‑up areas and surface reflectivity. It uses an empirical model that links LST to the previously processed cloud-free indices at coarse resolution and then applies this relationship to predict LST at finer resolution (e.g. 100 m or higher). The approach is based on a bilinear extension of the TsHARP method, ensuring stable and physically consistent results for urban environments.</li><li>For <strong>Smart Partitioning (Segmentation)</strong> a superpixel clustering algorithm (SLIC) is applied to group neighbouring areas with similar heat trends. It produces spatial zones that reflect homogeneous thermal behaviour, rather than administrative boundaries.</li><li>The <strong>Time Series Analysis (Trend Modelling)</strong> uses generalized additive models to analyse temperature trends over time. It separates effects like long-term trend, seasonality, and daily variation to provide robust and explainable results.</li></ol><p>The UHTM Service uses a cloud-based, containerized (Docker/Kubernetes) architecture, enabling scalable data processing, standardised APIs, and interactive web-based access.</p><p><img src="https://workspace-ui-public.gtif-at-sc.hub-otc.eox.at/api/public/share/public-4wazei3y-02/UHTM_Wien/UHTM_Wien.png" alt=""></p><p align="left"><em>Figure 1: Urban heat trend monitoring steps: from LST data to local heat trend analysis.</em></p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>The UHTM service is delivered via a cloud-based platform with an interactive web interface. Users can either access the service directly via a web browser or integrate it into external systems, such as digital twins of cities, using standardised APIs.</p><h2 id="provider" tabindex="-1">Provider <a class="header-anchor" href="#provider" aria-label="Permalink to &quot;Provider&quot;">​</a></h2><p>The <em>Urban Heat Trend Monitor</em> service was developed by <a href="https://ohb-dc.de/en/earth-observation-solutions/" target="_blank" rel="noreferrer">OHB Digital Connect GmbH</a> as part of the <em>BalticGTIF</em> and <em>GTIF-AT SC</em> projects for the <em>Sustainable Cities</em> priority area of the ESA’s <em><strong>Green Transition Information Factory</strong></em> (GTIF) programme <a href="https://gtif.esa.int" target="_blank" rel="noreferrer">[2]</a>.</p>',20))],64)):d("",!0)])]))}});export{v as __pageData,y as default};
